// src/fn/sot563.ts
import { z as z24 } from "zod";
import { length as length16 } from "circuit-json";
var sot563_def = base_def.extend({
  fn: z24.string(),
  num_pins: z24.literal(6).default(6),
  w: z24.string().default("2.1mm"),
  h: z24.string().default("2.45mm"),
  p: z24.string().default("0.5mm"),
  pl: z24.string().default("0.675mm"),
  pw: z24.string().default("0.35mm"),
  string: z24.string().optional()
});
var sot563 = (raw_params) => {
  const parameters = sot563_def.parse({ ...raw_params, fn: "sot563" });
  const w = length16.parse(parameters.w);
  const h = length16.parse(parameters.h);
  const p = length16.parse(parameters.p);
  const pl = length16.parse(parameters.pl);
  const pw = length16.parse(parameters.pw);
  const pads = [];
  for (let i = 0; i < 6; i++) {
    const { x, y } = getSot563PadCoord(i + 1, w, p, pl);
    pads.push(rectpad(i + 1, x, y, pl, pw));
  }
  const silkscreenTopLine = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: -w / 2, y: h / 2 },
      { x: w / 2, y: h / 2 }
    ],
    stroke_width: 0.05,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenBottomLine = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: -w / 2, y: -h / 2 },
      { x: w / 2, y: -h / 2 }
    ],
    stroke_width: 0.05,
    pcb_silkscreen_path_id: ""
  };
  const pin1Position = getSot563PadCoord(1, w, p, pl);
  const pin1Marking = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "pin_marker_1",
    route: [
      { x: pin1Position.x - pl / 2 - 0.3, y: pin1Position.y },
      { x: pin1Position.x - pl / 2 - 0.45, y: pin1Position.y + 0.15 },
      { x: pin1Position.x - pl / 2 - 0.45, y: pin1Position.y - 0.15 },
      { x: pin1Position.x - pl / 2 - 0.3, y: pin1Position.y }
    ],
    stroke_width: 0.05,
    pcb_silkscreen_path_id: "pin_marker_1"
  };
  const silkscreenRefText = silkscreenRef(0, h / 2 + 0.4, 0.25);
  return {
    circuitJson: [
      ...pads,
      silkscreenTopLine,
      silkscreenBottomLine,
      silkscreenRefText,
      pin1Marking
    ],
    parameters
  };
};
var getSot563PadCoord = (pn, w, p, pl) => {
  const padCenterOffset = w / 2 - pl / 2;
  if (pn <= 3) {
    return { x: -padCenterOffset, y: p - (pn - 1) * p };
  }
  return { x: padCenterOffset, y: -p + (pn - 4) * p };
};

