// src/fn/radial.ts
import {
  length as length20
} from "circuit-json";
import { z as z28 } from "zod";

// src/helpers/generateCircleArcs.ts
var generateCircleArcs = (centerX, centerY, radius, cut, cutHeight, segmentLength = 0.1) => {
  const topArc = [];
  const bottomArc = [];
  const segments = Math.max(1, Math.ceil(Math.PI * radius / segmentLength));
  const thetaStep = Math.PI / segments;
  for (let i = 0; i <= segments; i++) {
    const theta = i * thetaStep;
    const x = centerX + Math.cos(theta) * radius;
    const y = centerY + Math.sin(theta) * radius;
    if (x < centerX - cut && y >= centerY - cutHeight / 2 && y <= centerY + cutHeight / 2) {
      continue;
    }
    topArc.push({ x, y });
  }
  for (let i = 0; i <= segments; i++) {
    const theta = Math.PI + i * thetaStep;
    const x = centerX + Math.cos(theta) * radius;
    const y = centerY + Math.sin(theta) * radius;
    if (x < centerX - cut && y >= centerY - cutHeight / 2 && y <= centerY + cutHeight / 2) {
      continue;
    }
    bottomArc.push({ x, y });
  }
  return { topArc, bottomArc };
};

// src/fn/radial.ts
var radial_def = base_def.extend({
  fn: z28.string(),
  p: length20.optional().default("5mm"),
  id: length20.optional().default("0.8mm"),
  od: length20.optional().default("1.6mm"),
  ceramic: z28.boolean().optional(),
  electrolytic: z28.boolean().optional(),
  polarized: z28.boolean().optional()
});
var radial = (raw_params) => {
  const parameters = radial_def.parse(raw_params);
  const { p, id, od } = parameters;
  if (id === 0.8 && od === 1.6) {
    parameters.id = p === 5 ? 0.8 : p * 0.25;
    parameters.od = p === 5 ? 1.6 : p * 0.5;
  }
  const plated_holes = [
    platedhole(1, -p / 2, 0, parameters.id, parameters.od),
    platedhole(2, p / 2, 0, parameters.id, parameters.od)
  ];
  const bodyR = p + 0.1;
  const { topArc, bottomArc } = generateCircleArcs(
    0,
    0,
    bodyR,
    parameters.od / 2,
    parameters.od
  );
  const strokeWidth = 0.02 * p;
  const silkscreenBodyTop = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: topArc,
    stroke_width: strokeWidth,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenBodyBottom = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: bottomArc,
    stroke_width: strokeWidth,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenCenterLine = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: 0, y: bodyR },
      { x: 0, y: -bodyR }
    ],
    stroke_width: strokeWidth,
    pcb_silkscreen_path_id: ""
  };
  const plusSize = 0.1 * p;
  const plusX = -(p + plusSize + 0.04 * p);
  const plusY = bodyR - plusSize - 0.08 * p;
  const plusHoriz = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: plusX - plusSize, y: plusY },
      { x: plusX + plusSize, y: plusY }
    ],
    stroke_width: strokeWidth,
    pcb_silkscreen_path_id: ""
  };
  const plusVert = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: plusX, y: plusY - plusSize },
      { x: plusX, y: plusY + plusSize }
    ],
    stroke_width: strokeWidth,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenRefText = silkscreenRef(
    0,
    bodyR + 0.12 * p,
    0.1 * p
  );
  const circuitJson = [
    ...plated_holes,
    silkscreenBodyTop,
    silkscreenBodyBottom,
    silkscreenCenterLine,
    silkscreenRefText
  ];
  const hasPolarity = parameters.electrolytic === true || parameters.polarized === true;
  if (hasPolarity) {
    circuitJson.push(plusHoriz, plusVert);
  }
  return {
    circuitJson,
    parameters
  };
};

// src/fn/pushbutton.ts
import { length as length21 } from "circuit-json";
import { z as z29 } from "zod";

// src/helpers/silkscreenpath.ts
var silkscreenpath = (route, options = {}) => {
  return {
    type: "pcb_silkscreen_path",
    layer: options.layer || "top",
    pcb_component_id: options.pcb_component_id || "",
    pcb_silkscreen_path_id: options.pcb_silkscreen_path_id || "",
    route,
    stroke_width: options.stroke_width || 0.1
  };
};

// src/fn/pushbutton.ts
var pushbutton_def = base_def.extend({
  fn: z29.literal("pushbutton"),
  w: length21.default(4.5),
  h: length21.default(6.5),
  id: length21.default(1),
  od: length21.default(1.2)
});
var pushbutton = (raw_params) => {
  const parameters = pushbutton_def.parse(raw_params);
  const width = parameters.w;
  const height = parameters.h;
  const holeDiameter = parameters.id;
  const holes = [
    platedhole(1, -width / 2, height / 2, holeDiameter, holeDiameter * 1.5),
    platedhole(2, -width / 2, -height / 2, holeDiameter, holeDiameter * 1.5),
    platedhole(3, width / 2, -height / 2, holeDiameter, holeDiameter * 1.5),
    platedhole(4, width / 2, height / 2, holeDiameter, holeDiameter * 1.5)
  ];
  const silkscreenLines = [
    // Vertical lines indicating connections
    silkscreenpath([
      { x: -width / 2, y: -height / 2 },
      { x: -width / 2, y: height / 2 }
    ]),
    silkscreenpath([
      { x: width / 2, y: -height / 2 },
      { x: width / 2, y: height / 2 }
    ]),
    // Center indicating latch
    silkscreenpath([
      { x: -width / 2, y: 0 },
      { x: -width / 5, y: 0 },
      { x: width / 5 * 1 / Math.sqrt(2), y: height / 8 }
    ]),
    silkscreenpath([
      { x: width / 2, y: 0 },
      { x: width / 5, y: 0 }
    ])
  ];
  const silkscreenRefText = silkscreenRef(
    0,
    height / 2 + 0.4,
    0.5
  );
  return {
    circuitJson: [...holes, ...silkscreenLines, silkscreenRefText],
    parameters
  };
};

