// src/fn/breakoutheaders.ts
import {
  length as length24
} from "circuit-json";
import { z as z32 } from "zod";
var breakoutheaders_def = base_def.extend({
  fn: z32.string(),
  w: length24.default("10mm"),
  h: length24.optional(),
  left: length24.optional().default(20),
  right: length24.optional().default(20),
  top: length24.optional().default(0),
  bottom: length24.optional().default(0),
  p: length24.default(length24.parse("2.54mm")),
  id: length24.optional().default(length24.parse("1mm")),
  od: length24.optional().default(length24.parse("1.5mm"))
});
var getHeight3 = (parameters) => {
  const params = breakoutheaders_def.parse(parameters);
  if (params.left && params.right) {
    return Math.max(params.left, params.right) * params.p;
  }
  if (params.left) {
    return params.left * params.p;
  }
  if (params.right) {
    return params.right * params.p;
  }
  return 51;
};
var getTrianglePath = (x, y, side, triangleHeight = 1, triangleWidth = 0.6) => {
  const halfHeight = triangleHeight / 2;
  const halfWidth = triangleWidth / 2;
  const silkscreenTriangleRoutes = {
    left: [
      { x: x + halfHeight, y },
      { x: x - halfHeight, y: y + halfWidth },
      { x: x - halfHeight, y: y - halfWidth },
      { x: x + halfHeight, y }
    ],
    right: [
      { x: x - halfHeight, y },
      { x: x + halfHeight, y: y + halfWidth },
      { x: x + halfHeight, y: y - halfWidth },
      { x: x - halfHeight, y }
    ],
    top: [
      { x, y: y - halfHeight },
      { x: x - halfWidth, y: y + halfHeight },
      { x: x + halfWidth, y: y + halfHeight },
      { x, y: y - halfHeight }
    ],
    bottom: [
      { x, y: y + halfHeight },
      { x: x - halfWidth, y: y - halfHeight },
      { x: x + halfWidth, y: y - halfHeight },
      { x, y: y + halfHeight }
    ]
  };
  return silkscreenTriangleRoutes[side];
};
var breakoutheaders = (raw_params) => {
  const params = breakoutheaders_def.parse(raw_params);
  const height = params.h ?? getHeight3(params);
  const holes = [];
  const innerDiameter = params.id;
  const outerDiameter = params.od;
  let silkscreenTriangleRoutes = [];
  if (params.right) {
    const yoff = -((params.right - 1) / 2) * params.p;
    for (let i = 0; i < params.right; i++) {
      if (i === 0 && !params.left && !params.bottom) {
        silkscreenTriangleRoutes = getTrianglePath(
          params.w / 2 + outerDiameter * 1.4,
          yoff + i * params.p,
          "right"
        );
      }
      holes.push(
        platedhole(
          i + 1 + params.left + (params.bottom ?? 0),
          params.w / 2,
          yoff + i * params.p,
          innerDiameter,
          outerDiameter
        )
      );
    }
  }
  if (params.left) {
    const yoff = -((params.left - 1) / 2) * params.p;
    for (let i = 0; i < params.left; i++) {
      if (i === params.left - 1) {
        silkscreenTriangleRoutes = getTrianglePath(
          -params.w / 2 - outerDiameter * 1.4,
          yoff + i * params.p,
          "left"
        );
      }
      holes.push(
        platedhole(
          i + 1,
          -params.w / 2,
          yoff + i * params.p,
          innerDiameter,
          outerDiameter
        )
      );
    }
  }
  if (params.top) {
    const xoff = -((params.top - 1) / 2) * params.p;
    for (let i = 0; i < params.top; i++) {
      if (i === params.top - 1 && !params.left && !params.bottom && !params.right) {
        silkscreenTriangleRoutes = getTrianglePath(
          xoff + i * params.p,
          height / 2 + outerDiameter * 1.4,
          "top"
        );
      }
      holes.push(
        platedhole(
          i + 1 + params.right + (params.bottom ?? 0) + params.left,
          xoff + i * params.p,
          height / 2,
          innerDiameter,
          outerDiameter
        )
      );
    }
  }
  if (params.bottom) {
    const xoff = -((params.bottom - 1) / 2) * params.p;
    for (let i = 0; i < params.bottom; i++) {
      if (i === 0 && !params.left) {
        silkscreenTriangleRoutes = getTrianglePath(
          xoff + i * params.p,
          -height / 2 - outerDiameter * 1.4,
          "bottom"
        );
      }
      holes.push(
        platedhole(
          i + 1 + params.left,
          xoff + i * params.p,
          -height / 2,
          innerDiameter,
          outerDiameter
        )
      );
    }
  }
  const silkscreenTriangle = {
    type: "pcb_silkscreen_path",
    pcb_silkscreen_path_id: "1",
    pcb_component_id: "1",
    layer: "top",
    route: silkscreenTriangleRoutes,
    stroke_width: 0.1
  };
  const silkscreenPath = {
    type: "pcb_silkscreen_path",
    pcb_silkscreen_path_id: "pcb_silkscreen_path_1",
    pcb_component_id: "1",
    route: [
      {
        x: -params.w / 2 - outerDiameter,
        y: height / 2 + outerDiameter
      },
      {
        x: params.w / 2 + outerDiameter,
        y: height / 2 + outerDiameter
      },
      {
        x: params.w / 2 + outerDiameter,
        y: -height / 2 - outerDiameter
      },
      {
        x: -params.w / 2 - outerDiameter,
        y: -height / 2 - outerDiameter
      },
      {
        x: -params.w / 2 - outerDiameter,
        y: height / 2 + outerDiameter
      }
    ],
    stroke_width: 0.1,
    layer: "top"
  };
  const silkscreenRefText = silkscreenRef(
    0,
    height / 1.7,
    height / 25
  );
  return {
    circuitJson: [
      ...holes,
      silkscreenPath,
      silkscreenRefText,
      silkscreenTriangle
    ],
    parameters: params
  };
};

// src/fn/hc49.ts
import {
  length as length25
} from "circuit-json";
import { z as z33 } from "zod";
var generate_u_curve = (centerX, centerY, radius, direction) => {
  return Array.from({ length: 25 }, (_, i) => {
    const theta = i / 24 * Math.PI - Math.PI / 2;
    return {
      x: centerX + (direction === "right" ? 1 : -1) * Math.cos(theta) * radius,
      y: centerY + Math.sin(theta) * radius
    };
  });
};
var hc49_def = base_def.extend({
  fn: z33.string(),
  p: length25.optional().default("4.88mm"),
  id: length25.optional().default("0.8mm"),
  od: length25.optional().default("1.5mm"),
  w: length25.optional().default("5.6mm"),
  h: length25.optional().default("3.5mm")
});
var hc49 = (raw_params) => {
  const parameters = hc49_def.parse(raw_params);
  const { p, id, od, w, h } = parameters;
  const radius = h / 2;
  const plated_holes = [
    platedhole(1, -p / 2, 0, id, od),
    platedhole(2, p / 2, 0, id, od)
  ];
  const leftCurve = generate_u_curve(-w / 2, 0, radius, "left");
  const rightCurve = generate_u_curve(w / 2, 0, radius, "right");
  const silkscreenBody = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      ...leftCurve,
      ...leftCurve.slice(1).reverse(),
      { x: -w / 2, y: -h / 2 },
      { x: w / 2, y: -h / 2 },
      ...rightCurve,
      { x: w / 2, y: h / 2 },
      { x: -w / 2, y: h / 2 }
    ],
    stroke_width: 0.1,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenRefText = silkscreenRef(0, p / 4, 0.5);
  return {
    circuitJson: [
      ...plated_holes,
      silkscreenBody,
      silkscreenRefText
    ],
    parameters
  };
};

