// src/fn/to92.ts
var to92_def = base_def.extend({
  fn: z35.string(),
  num_pins: z35.union([z35.literal(3), z35.literal(2)]).default(3),
  p: z35.string().default("1.27mm"),
  id: z35.string().default("0.72mm"),
  od: z35.string().default("0.95mm"),
  w: z35.string().default("4.5mm"),
  h: z35.string().default("4.5mm"),
  inline: z35.boolean().default(false),
  string: z35.string().optional()
});
var generateSemicircle = (centerX, centerY, radius) => {
  return Array.from({ length: 25 }, (_, i) => {
    const theta = i / 24 * Math.PI;
    return {
      x: centerX + Math.cos(theta) * radius,
      y: centerY + Math.sin(theta) * radius
    };
  });
};
var to92 = (raw_params) => {
  const match = raw_params.string?.match(/^to92_(\d+)/);
  const numPins = match ? Number.parseInt(match[1], 10) : 3;
  const parameters = to92_def.parse({
    ...raw_params,
    num_pins: numPins
  });
  const { p, id, od, w, h, inline } = parameters;
  const holeY = Number.parseFloat(h) / 2;
  const padSpacing7 = Number.parseFloat(p);
  const holeDia = Number.parseFloat(id);
  const padDia = Number.parseFloat(od);
  const padWidth = padDia;
  const padHeight = padDia * (1.5 / 1.05);
  let platedHoles = [];
  if (parameters.num_pins === 3) {
    if (inline) {
      platedHoles = [
        platedHoleWithRectPad({
          pn: 1,
          x: -padSpacing7,
          y: holeY - padSpacing7,
          holeDiameter: holeDia,
          rectPadWidth: padDia,
          rectPadHeight: padHeight
        }),
        platedHolePill(2, 0, holeY - padSpacing7, holeDia, padWidth, padHeight),
        platedHolePill(
          3,
          padSpacing7,
          holeY - padSpacing7,
          holeDia,
          padWidth,
          padHeight
        )
      ];
    } else {
      platedHoles = [
        platedHoleWithRectPad({
          pn: 1,
          x: -padSpacing7,
          y: holeY - padSpacing7,
          holeDiameter: holeDia,
          rectPadWidth: padDia,
          rectPadHeight: padDia
        }),
        platedhole(2, 0, holeY, holeDia, padDia),
        platedhole(3, padSpacing7, holeY - padSpacing7, holeDia, padDia)
      ];
    }
  } else if (parameters.num_pins === 2) {
    platedHoles = [
      platedHoleWithRectPad({
        pn: 1,
        x: -padSpacing7,
        y: holeY - padSpacing7,
        holeDiameter: holeDia,
        rectPadWidth: padWidth,
        rectPadHeight: padHeight
      }),
      platedHolePill(
        2,
        padSpacing7,
        holeY - padSpacing7,
        holeDia,
        padWidth,
        padHeight
      )
    ];
  } else {
    throw new Error("Invalid number of pins for TO-92");
  }
  const radius = Number.parseFloat(w) / 2;
  const semicircle = generateSemicircle(0, holeY, radius);
  const silkscreenBody = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      ...semicircle,
      { x: -radius, y: 0 },
      { x: radius, y: 0 },
      semicircle[0]
    ],
    stroke_width: 0.1,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenRefText = silkscreenRef(0, holeY + 1, 0.5);
  return {
    circuitJson: [
      ...platedHoles,
      silkscreenBody,
      silkscreenRefText
    ],
    parameters
  };
};

