import {
  length as length38
} from "circuit-json";
import { z as z48 } from "zod";
var to220_def = base_def.extend({
  fn: z48.string(),
  p: length38.optional().default("5.0mm"),
  id: length38.optional().default("1.0mm"),
  od: length38.optional().default("1.9mm"),
  w: length38.optional().default("13mm"),
  h: length38.optional().default("7mm"),
  num_pins: z48.number().optional(),
  string: z48.string().optional()
});
var to220 = (raw_params) => {
  const parameters = to220_def.parse(raw_params);
  const { id, od, w, h, string: string3 } = parameters;
  const numPins = parameters.num_pins ?? Number.parseInt(string3?.match(/^to220(?:_|-)(\d+)/i)?.[1] ?? "3");
  const holeY = -1;
  const halfWidth = w / 2;
  const halfHeight = h / 2;
  const minPitch = 2.5;
  const maxHoleWidth = w * 0.4;
  const computedPitch = Math.max(minPitch, maxHoleWidth / (numPins - 1));
  const plated_holes = Array.from({ length: numPins }, (_, i) => {
    const x = numPins % 2 === 0 ? (i - numPins / 2 + 0.5) * computedPitch : (i - Math.floor(numPins / 2)) * computedPitch;
    return platedhole(i + 1, x, holeY, id, od);
  });
  const silkscreenBody = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: -halfWidth, y: -halfHeight },
      { x: halfWidth, y: -halfHeight },
      { x: halfWidth, y: halfHeight },
      { x: -halfWidth, y: halfHeight },
      { x: -halfWidth, y: -halfHeight }
    ],
    stroke_width: 0.1,
    pcb_silkscreen_path_id: ""
  };
  const yLine = -halfHeight + 2 * h / 3;
  const horizontalLine = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: -halfWidth, y: yLine },
      { x: halfWidth, y: yLine }
    ],
    stroke_width: 0.1,
    pcb_silkscreen_path_id: ""
  };
  const verticalLines = [
    {
      type: "pcb_silkscreen_path",
      layer: "top",
      pcb_component_id: "",
      route: [
        { x: -w / 6, y: yLine },
        { x: -w / 6, y: halfHeight }
      ],
      stroke_width: 0.1,
      pcb_silkscreen_path_id: ""
    },
    {
      type: "pcb_silkscreen_path",
      layer: "top",
      pcb_component_id: "",
      route: [
        { x: w / 6, y: yLine },
        { x: w / 6, y: halfHeight }
      ],
      stroke_width: 0.1,
      pcb_silkscreen_path_id: ""
    }
  ];
  const silkscreenRefText = silkscreenRef(0, h / 2 + 0.6, 0.5);
  return {
    circuitJson: [
      ...plated_holes,
      silkscreenBody,
      horizontalLine,
      ...verticalLines,
      silkscreenRefText
    ],
    parameters: { ...parameters, p: computedPitch }
  };
};

// src/fn/to220f.ts
import { mm as mm14 } from "@tscircuit/mm";
import { length as length39 } from "circuit-json";
import { z as z49 } from "zod";
var TO220F_PITCH_MM = 2.54;
var to220f_def = base_def.extend({
  fn: z49.string(),
  // KiCad TO-220F-3_Vertical: hole=1.2mm, pad=1.905×2.0mm, pitch=2.54mm
  id: length39.optional().default("1.2mm"),
  od: length39.optional().default("1.905mm"),
  ph: length39.optional().default("2mm"),
  w: length39.optional().default("13mm"),
  h: length39.optional().default("7mm"),
  num_pins: z49.number().optional(),
  string: z49.string().optional()
});
var to220f = (raw_params) => {
  const parameters = to220f_def.parse(raw_params);
  const numPins = parameters.num_pins ?? Number.parseInt(
    parameters.string?.match(/^to220f(?:_|-)(\d+)/i)?.[1] ?? "3"
  );
  const baseResult = to220({
    ...parameters,
    fn: "to220",
    string: parameters.string?.replace(/^to220f/i, "to220"),
    num_pins: numPins
  });
  const holeY = -1;
  const newHoles = Array.from(
    { length: numPins },
    (_, i) => {
      const x = numPins % 2 === 0 ? (i - numPins / 2 + 0.5) * TO220F_PITCH_MM : (i - Math.floor(numPins / 2)) * TO220F_PITCH_MM;
      if (i === 0) {
        return platedHoleWithRectPad({
          pn: 1,
          x,
          y: holeY,
          holeDiameter: parameters.id,
          rectPadWidth: parameters.od,
          rectPadHeight: parameters.ph
        });
      }
      return platedHolePill(
        i + 1,
        x,
        holeY,
        mm14(parameters.id),
        mm14(parameters.od),
        mm14(parameters.ph)
      );
    }
  );
  const nonHoleElements = baseResult.circuitJson.filter(
    (e) => e.type !== "pcb_plated_hole"
  );
  return {
    circuitJson: [...newHoles, ...nonHoleElements],
    parameters: { ...parameters, p: TO220F_PITCH_MM, num_pins: numPins }
  };
};

