// src/fn/to92s.ts
import { z as z60 } from "zod";
var to92s_def = base_def.extend({
  fn: z60.string(),
  num_pins: z60.union([z60.literal(3), z60.literal(2)]).default(3),
  p: z60.string().default("1.27mm"),
  id: z60.string().default("0.72mm"),
  od: z60.string().default("0.95mm"),
  w: z60.string().default("2.5mm"),
  h: z60.string().default("4.2mm"),
  string: z60.string().optional()
});
var to92s_3 = (parameters) => {
  const { p, id, od, w, h } = parameters;
  const holeY = Number.parseFloat(h) / 2;
  const padSpacing7 = Number.parseFloat(p);
  return [
    platedhole(1, -padSpacing7, holeY - padSpacing7, id, od),
    platedhole(2, 0, holeY - padSpacing7, id, od),
    platedhole(3, padSpacing7, holeY - padSpacing7, id, od)
  ];
};
var to92s_2 = (parameters) => {
  const { p, id, od, h } = parameters;
  const holeY = Number.parseFloat(h) / 2;
  const padSpacing7 = Number.parseFloat(p);
  return [
    platedhole(1, -padSpacing7, holeY - padSpacing7, id, od),
    platedhole(2, padSpacing7, holeY - padSpacing7, id, od)
  ];
};
var to92s = (raw_params) => {
  const match = raw_params.string?.match(/^to92s_(\d+)/);
  const numPins = match ? Number.parseInt(match[1], 10) : 3;
  const parameters = to92s_def.parse({
    ...raw_params,
    num_pins: numPins
  });
  let platedHoles = [];
  if (parameters.num_pins === 3) {
    platedHoles = to92s_3(parameters);
  } else if (parameters.num_pins === 2) {
    platedHoles = to92s_2(parameters);
  } else {
    throw new Error("Invalid number of pins for TO-92");
  }
  const holeY = Number.parseFloat(parameters.h) / 2;
  const padSpacing7 = Number.parseFloat(parameters.p);
  const silkscreenBody = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "",
    route: [
      { x: -holeY, y: holeY - padSpacing7 },
      { x: -1.9, y: 0 },
      { x: 1.9, y: 0 },
      { x: holeY, y: holeY - padSpacing7 },
      { x: 1.5, y: Number.parseFloat(parameters.h) / 2 + 0.5 },
      { x: -1.5, y: Number.parseFloat(parameters.h) / 2 + 0.5 },
      { x: -holeY, y: holeY - padSpacing7 }
    ],
    stroke_width: 0.1,
    pcb_silkscreen_path_id: ""
  };
  const silkscreenRefText = silkscreenRef(0, holeY + 1, 0.5);
  return {
    circuitJson: [
      ...platedHoles,
      silkscreenBody,
      silkscreenRefText
    ],
    parameters
  };
};

// src/fn/jst.ts
import {
  length as length48
} from "circuit-json";
import { z as z61 } from "zod";
var jst_def = base_def.extend({
  fn: z61.string(),
  p: length48.optional(),
  id: length48.optional(),
  pw: length48.optional(),
  pl: length48.optional(),
  w: length48.optional(),
  h: length48.optional(),
  sh: z61.boolean().optional().describe(
    'JST SH (Surface-mount) connector family. SH stands for "Super High-density".'
  ),
  ph: z61.boolean().optional().describe(
    'JST PH (Through-hole) connector family. PH stands for "Pin Header".'
  ),
  zh: z61.boolean().optional().describe(
    "JST ZH (Through-hole) connector family. 1.5mm pitch wire-to-board."
  ),
  string: z61.string().optional()
});
var variantDefaults = {
  ph: {
    p: length48.parse("2.2mm"),
    id: length48.parse("0.70mm"),
    pw: length48.parse("1.20mm"),
    pl: length48.parse("1.20mm"),
    w: length48.parse("6mm"),
    h: length48.parse("5mm")
  },
  sh: {
    p: length48.parse("1mm"),
    pw: length48.parse("0.6mm"),
    pl: length48.parse("1.55mm"),
    w: length48.parse("5.8mm"),
    h: length48.parse("7.8mm")
  },
  zh: {
    p: length48.parse("1.5mm"),
    id: length48.parse("0.73mm"),
    pw: length48.parse("1.03mm"),
    pl: length48.parse("1.73mm"),
    w: length48.parse("3mm"),
    h: length48.parse("3.5mm")
  }
};
function getVariant(params) {
  if (params.sh) return "sh";
  if (params.ph) return "ph";
  if (params.zh) return "zh";
  return "ph";
}
function generatePads(variant, numPins, p, id, pw, pl) {
  const pads = [];
  if (variant === "ph") {
    const startX = -((numPins - 1) / 2) * p;
    for (let i = 0; i < numPins; i++) {
      const x = startX + i * p;
      pads.push(
        platedHoleWithRectPad({
          pn: i + 1,
          x,
          y: 2,
          holeDiameter: id,
          rectPadWidth: pw,
          rectPadHeight: pl
        })
      );
    }
  } else if (variant === "zh") {
    const startX = -((numPins - 1) / 2) * p;
    for (let i = 0; i < numPins; i++) {
      const x = startX + i * p;
      if (i === 0) {
        pads.push(
          platedHoleWithRectPad({
            pn: i + 1,
            x,
            y: 0,
            holeDiameter: id,
            rectPadWidth: pw,
            rectPadHeight: pl,
            rectBorderRadius: 0.12499977
          })
        );
      } else {
        pads.push(platedHolePill(i + 1, x, 0, id, pw, pl));
      }
    }
  } else {
    const startX = -((numPins - 1) / 2) * p;
    for (let i = 0; i < numPins; i++) {
      const x = startX + i * p;
      pads.push(rectpad(i + 1, x, -1.325, pw, pl));
    }
    const sideOffset = (numPins - 1) / 2 * p + 1.3;
    pads.push(rectpad(numPins + 1, -sideOffset, 1.22, 1.2, 1.8));
    pads.push(rectpad(numPins + 2, sideOffset, 1.22, 1.2, 1.8));
  }
  return pads;
}
function generateSilkscreenBody(variant, w, h, numPins, p) {
  if (variant === "ph") {
    return {
      type: "pcb_silkscreen_path",
      layer: "top",
      pcb_component_id: "",
      route: [
        { x: -3, y: 3 },
        { x: 3, y: 3 },
        { x: 3, y: -2 },
        { x: -3, y: -2 },
        { x: -3, y: 3 }
      ],
      stroke_width: 0.1,
      pcb_silkscreen_path_id: ""
    };
  } else if (variant === "zh" && numPins && p) {
    const pinSpan = (numPins - 1) * p;
    const bodyLeft = -pinSpan / 2 - 1.5;
    const bodyRight = pinSpan / 2 + 1.5;
    const bodyTop = -h / 2;
    const bodyBottom = h / 2;
    return {
      type: "pcb_silkscreen_path",
      layer: "top",
      pcb_component_id: "",
      route: [
        { x: bodyLeft, y: bodyTop },
        { x: bodyRight, y: bodyTop },
        { x: bodyRight, y: bodyBottom },
        { x: bodyLeft, y: bodyBottom },
        { x: bodyLeft, y: bodyTop }
      ],
      stroke_width: 0.1,
      pcb_silkscreen_path_id: ""
    };
  } else {
    return {
      type: "pcb_silkscreen_path",
      layer: "top",
      pcb_component_id: "",
      route: [],
      stroke_width: 0.1,
      pcb_silkscreen_path_id: ""
    };
  }
}
