import { z as z79 } from "zod";
var m2host_def = base_def.extend({
  fn: z79.string()
});
var m2host = (raw_params) => {
  const parameters = m2host_def.parse(raw_params);
  const pads = [];
  const padWidth = 0.5 - 0.15;
  const padLength = 1.5;
  const pitch = 0.5;
  const halfPitch = pitch / 2;
  const rowOffset = 0.5;
  const numPads = 75;
  const startY = -((numPads - 1) * pitch) / 2;
  for (let i = 0; i < numPads; i++) {
    const pn = i + 1;
    if (pn >= 24 && pn <= 31) continue;
    const y = startY - i * halfPitch;
    const isBottomLayer = pn % 2 === 0;
    const padLengthWithOffset = padLength + (isBottomLayer ? 0.25 : 0);
    const rightEdgeOffset = 0.5;
    const x = rightEdgeOffset - padLengthWithOffset / 2;
    const pad2 = rectpad(pn, x, y, padLengthWithOffset, padWidth);
    pad2.layer = isBottomLayer ? "bottom" : "top";
    pads.push(pad2);
  }
  const cutoutWidth = 46 * 0.0254;
  const cutoutDepth = 137 * 0.0254;
  const cutoutOffsetFromPin1 = 261 * 0.0254;
  const cutout = {
    type: "pcb_cutout",
    pcb_cutout_id: "",
    shape: "rect",
    center: {
      x: -cutoutDepth / 2 + padLength / 2,
      y: startY - cutoutOffsetFromPin1
    },
    width: cutoutDepth,
    height: cutoutWidth
  };
  const pin1MarkerPosition = {
    x: -0.5,
    y: startY
  };
  const pin1Marker = {
    type: "pcb_silkscreen_path",
    layer: "top",
    pcb_component_id: "pin_marker_1",
    route: [
      { x: pin1MarkerPosition.x - 0.4, y: pin1MarkerPosition.y },
      { x: pin1MarkerPosition.x - 0.7, y: pin1MarkerPosition.y + 0.3 },
      { x: pin1MarkerPosition.x - 0.7, y: pin1MarkerPosition.y - 0.3 },
      { x: pin1MarkerPosition.x - 0.4, y: pin1MarkerPosition.y }
    ],
    stroke_width: 0.05,
    pcb_silkscreen_path_id: "pin_marker_1"
  };
  let minX = Infinity;
  let maxX = -Infinity;
  let minY = Infinity;
  let maxY = -Infinity;
  const updateBounds = (x, y, w = 0, h = 0) => {
    minX = Math.min(minX, x - w / 2);
    maxX = Math.max(maxX, x + w / 2);
    minY = Math.min(minY, y - h / 2);
    maxY = Math.max(maxY, y + h / 2);
  };
  for (const pad2 of pads) {
    const rectPad = pad2;
    updateBounds(rectPad.x, rectPad.y, rectPad.width, rectPad.height);
  }
  updateBounds(cutout.center.x, cutout.center.y, cutout.width, cutout.height);
  for (const point of pin1Marker.route) {
    updateBounds(point.x, point.y);
  }
  const centerX = (minX + maxX) / 2;
  const centerY = (minY + maxY) / 2;
  const translate = (el) => {
    if (typeof el.x === "number") el.x -= centerX;
    if (typeof el.y === "number") el.y -= centerY;
    if (el.center) {
      el.center.x -= centerX;
      el.center.y -= centerY;
    }
    if (Array.isArray(el.route)) {
      el.route = el.route.map((p) => ({
        x: p.x - centerX,
        y: p.y - centerY
      }));
    }
  };
  for (const pad2 of pads) translate(pad2);
  translate(cutout);
  translate(pin1Marker);
  return {
    circuitJson: [
      ...pads,
      cutout,
      // silkscreenRefText,
      pin1Marker
    ],
    parameters
  };
};

